<?php declare(strict_types=1);
namespace App\Services;
use App\Infrastructure\Database;
final class HealthCheckService { public function __construct(private Database $database,private SettingsService $settings){} public function report(?array $stream):array{$s=$this->settings->all();$probe=fn(string $path):array=>['path'=>$path,'exists'=>is_file($path),'executable'=>is_executable($path)];try{$this->database->connection()->query('SELECT 1');$database='healthy';}catch(\Throwable){$database='unavailable';}$upload=config('settings.upload_directory');$logs=config('settings.log_directory');return ['php'=>PHP_VERSION,'app_timezone'=>$s['timezone'],'server_timezone'=>date_default_timezone_get(),'database'=>$database,'ffmpeg'=>$probe($s['ffmpeg_path']),'ytdlp'=>$probe($s['ytdlp_path']),'uploads'=>['path'=>$upload,'readable'=>is_readable($upload),'writable'=>is_writable($upload)],'logs'=>['path'=>$logs,'writable'=>is_writable($logs)],'disk_free_bytes'=>disk_free_space($upload)?:0,'stream_pid'=>$stream['pid']??null,'stream_log'=>$stream?($logs.'/stream-'.$stream['id'].'.log'):null];} }
